package e2e

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"testing"
	"time"

	"github.com/iw2rmb/ploy/internal/testutils"
)

type TestEnvironment struct {
	Config       Config
	TransflowCLI *TransflowCLI
	cleanup      []func()
}

type Config struct {
	UseRealServices bool
	CleanupAfter    bool
	InjectFailures  bool
	TimeoutMinutes  int
}

func SetupTestEnvironment(t *testing.T, config Config) *TestEnvironment {
	env := &TestEnvironment{Config: config}

	if config.UseRealServices {
		env.setupRealServices(t)
	} else {
		env.setupMockServices(t)
	}

	return env
}

func (env *TestEnvironment) setupRealServices(t *testing.T) {
	if os.Getenv("TARGET_HOST") != "" {
		env.setupVPSServices(t)
	} else {
		testutils.RequireServices(t, "consul", "nomad", "seaweedfs")
		env.setupLocalServices(t)
	}
}

func (env *TestEnvironment) setupLocalServices(t *testing.T) {
	env.TransflowCLI = &TransflowCLI{
		binaryPath: "./bin/ploy",
		env: map[string]string{
			"CONSUL_HTTP_ADDR":  "localhost:8500",
			"NOMAD_ADDR":        "http://localhost:4646",
			"SEAWEEDFS_MASTER":  "http://localhost:9333",
			"SEAWEEDFS_FILER":   "http://localhost:8888",
		},
	}
}

func (env *TestEnvironment) setupVPSServices(t *testing.T) {
	targetHost := os.Getenv("TARGET_HOST")
	env.TransflowCLI = &TransflowCLI{
		binaryPath: "./bin/ploy-linux",
		env: map[string]string{
			"TARGET_HOST": targetHost,
		},
	}
}

func (env *TestEnvironment) setupMockServices(t *testing.T) {
	env.TransflowCLI = &TransflowCLI{
		binaryPath: "./bin/ploy",
		env: map[string]string{
			"TRANSFLOW_TEST_MODE": "true",
		},
	}
}

func (env *TestEnvironment) ExecuteWorkflow(ctx context.Context, workflow *TransflowWorkflow) (WorkflowResult, error) {
	yamlContent, err := workflow.ToYAML()
	if err != nil {
		return WorkflowResult{}, fmt.Errorf("failed to generate workflow YAML: %w", err)
	}

	tempFile := filepath.Join(os.TempDir(), fmt.Sprintf("transflow-%s.yaml", workflow.ID))
	err = os.WriteFile(tempFile, []byte(yamlContent), 0644)
	if err != nil {
		return WorkflowResult{}, fmt.Errorf("failed to write workflow file: %w", err)
	}
	defer os.Remove(tempFile)

	start := time.Now()
	output, err := env.TransflowCLI.Run(ctx, "transflow", "run", "-f", tempFile)
	duration := time.Since(start)

	result := WorkflowResult{
		ID:       workflow.ID,
		Duration: duration,
		Success:  err == nil,
		Output:   output,
	}

	if err != nil {
		result.Error = err.Error()
	}

	result.parseFromOutput(output)
	return result, nil
}

func (env *TestEnvironment) Cleanup() {
	for _, cleanup := range env.cleanup {
		cleanup()
	}
}

type TransflowCLI struct {
	binaryPath string
	env        map[string]string
}

func (cli *TransflowCLI) Run(ctx context.Context, args ...string) (string, error) {
	if os.Getenv("TARGET_HOST") != "" {
		return cli.runVPS(ctx, args...)
	}
	return cli.runLocal(ctx, args...)
}

func (cli *TransflowCLI) runLocal(ctx context.Context, args ...string) (string, error) {
	cmd := exec.CommandContext(ctx, cli.binaryPath, args...)
	cmd.Env = os.Environ()
	for k, v := range cli.env {
		cmd.Env = append(cmd.Env, fmt.Sprintf("%s=%s", k, v))
	}
	output, err := cmd.CombinedOutput()
	return string(output), err
}

func (cli *TransflowCLI) runVPS(ctx context.Context, args ...string) (string, error) {
	targetHost := os.Getenv("TARGET_HOST")
	cmdArgs := append([]string{
		fmt.Sprintf("root@%s", targetHost),
		"su - ploy -c", 
		fmt.Sprintf("'/opt/ploy/bin/ploy %s'", args[0])}, args[1:]...)

	if len(args) > 1 {
		cmdArgs[2] = fmt.Sprintf("'/opt/ploy/bin/ploy %s'", fmt.Sprintf("%s %s", args[0], args[1]))
		if len(args) > 2 {
			for _, arg := range args[2:] {
				cmdArgs[2] += " " + arg
			}
		}
	}

	cmd := exec.CommandContext(ctx, "ssh", "-o", "ConnectTimeout=30", cmdArgs[0], cmdArgs[1], cmdArgs[2])
	output, err := cmd.CombinedOutput()
	return string(output), err
}

package e2e

import (
	"fmt"
	"regexp"
	"strings"
	"time"
)

type TransflowWorkflow struct {
	ID              string
	Repository      string
	TargetBranch    string
	Steps           []WorkflowStep
	SelfHeal        SelfHealConfig
	ExpectedOutcome Outcome
	MaxDuration     time.Duration
}

type WorkflowStep struct {
	Type    string
	ID      string
	Engine  string
	Recipes []string
}

type SelfHealConfig struct {
	Enabled    bool
	MaxRetries int
	KBLearning bool
}

type Outcome int

const (
	OutcomeSuccess Outcome = iota
	OutcomeHealedSuccess
	OutcomeFailure
)

type WorkflowResult struct {
	ID                   string
	Duration             time.Duration
	Success              bool
	Output               string
	Error                string
	WorkflowBranch       string
	BuildVersion         string
	MRUrl                string
	InitialBuildSuccess  bool
	HealingAttempted     bool
	HealingAttempts      []HealingAttempt
	ResourceUsage        *ResourceStats
}

type HealingAttempt struct {
	ErrorSignature string
	Success        bool
	Patch          string
	Confidence     float64
}

type ResourceStats struct {
	MaxMemoryMB int
	CPUPercent  float64
}

func (w *TransflowWorkflow) ToYAML() (string, error) {
	yaml := fmt.Sprintf(`version: v1alpha1
id: %s
target_repo: %s
target_branch: refs/heads/%s
base_ref: refs/heads/%s
lane: C
build_timeout: 10m

steps:
`, w.ID, w.Repository, w.TargetBranch, w.TargetBranch)

	for _, step := range w.Steps {
		yaml += fmt.Sprintf(`  - type: %s
    id: %s
    engine: %s
    recipes:
`, step.Type, step.ID, step.Engine)

		for _, recipe := range step.Recipes {
			yaml += fmt.Sprintf(`      - %s
`, recipe)
		}
	}

	if w.SelfHeal.Enabled {
		yaml += fmt.Sprintf(`
self_heal:
  enabled: true
  kb_learning: %t
  max_retries: %d
  cooldown: 30s
`, w.SelfHeal.KBLearning, w.SelfHeal.MaxRetries)
	}

	return yaml, nil
}

func (r *WorkflowResult) parseFromOutput(output string) {
	// Parse workflow branch
	branchRegex := regexp.MustCompile(`(?i)branch:\s+([^\s]+)`)
	if matches := branchRegex.FindStringSubmatch(output); len(matches) > 1 {
		r.WorkflowBranch = matches[1]
	}

	// Parse build version
	versionRegex := regexp.MustCompile(`(?i)build.version:\s+([^\s]+)`)
	if matches := versionRegex.FindStringSubmatch(output); len(matches) > 1 {
		r.BuildVersion = matches[1]
	}

	// Parse MR URL
	mrRegex := regexp.MustCompile(`(?i)merge.request:\s+(https://[^\s]+)`)
	if matches := mrRegex.FindStringSubmatch(output); len(matches) > 1 {
		r.MRUrl = matches[1]
	}

	// Parse healing attempts
	r.HealingAttempted = strings.Contains(strings.ToLower(output), "healing")
	r.InitialBuildSuccess = !strings.Contains(strings.ToLower(output), "build failed")

	// Parse healing details
	if strings.Contains(strings.ToLower(output), "healing attempt") {
		attempts := parseHealingAttempts(output)
		r.HealingAttempts = attempts
	}
}

package e2e

import (
	"regexp"
	"strconv"
	"strings"
)

func parseHealingAttempts(output string) []HealingAttempt {
	var attempts []HealingAttempt

	// Simple parsing for healing attempts from output
	lines := strings.Split(output, "\n")

	var currentAttempt *HealingAttempt

	for _, line := range lines {
		line = strings.TrimSpace(line)

		// Look for healing attempt markers
		if strings.Contains(strings.ToLower(line), "healing attempt") {
			if currentAttempt != nil {
				attempts = append(attempts, *currentAttempt)
			}
			currentAttempt = &HealingAttempt{}
		}

		if currentAttempt == nil {
			continue
		}

		// Parse error signature
		if strings.Contains(strings.ToLower(line), "error signature") || 
		   strings.Contains(strings.ToLower(line), "error:") {
			currentAttempt.ErrorSignature = extractErrorSignature(line)
		}

		// Parse success
		if strings.Contains(strings.ToLower(line), "success") &&
		   strings.Contains(strings.ToLower(line), "healing") {
			currentAttempt.Success = true
		}

		// Parse confidence
		confidenceRegex := regexp.MustCompile(`confidence:\s+([0-9.]+)`)
		if matches := confidenceRegex.FindStringSubmatch(line); len(matches) > 1 {
			if conf, err := strconv.ParseFloat(matches[1], 64); err == nil {
				currentAttempt.Confidence = conf
			}
		}
	}

	if currentAttempt != nil {
		attempts = append(attempts, *currentAttempt)
	}

	return attempts
}

func extractErrorSignature(line string) string {
	// Extract error signature from line
	if idx := strings.Index(strings.ToLower(line), "error"); idx != -1 {
		remaining := line[idx:]
		if colonIdx := strings.Index(remaining, ":"); colonIdx != -1 {
			sig := strings.TrimSpace(remaining[colonIdx+1:])
			if len(sig) > 100 {
				sig = sig[:100] + "..."
			}
			return sig
		}
	}
	return "unknown-error"
}
